import { NextRequest, NextResponse } from "next/server";
import { auth } from "@clerk/nextjs/server";
import { prisma } from "@atlas/db";
import { z } from "zod";

const AlertPrefUpdateSchema = z.object({
  mode: z.enum(["immediate", "off"]),
  severityFloor: z.enum(["warning", "critical"]),
  agentId: z.string().optional(),
});

async function resolveOrg(clerkOrgId: string) {
  return prisma.organization.findUnique({
    where: { clerkOrgId },
    select: { id: true },
  });
}

export async function GET(req: NextRequest) {
  const { orgId: clerkOrgId } = await auth();
  if (!clerkOrgId) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const org = await resolveOrg(clerkOrgId);
  if (!org) {
    return NextResponse.json({ error: "Organization not found" }, { status: 404 });
  }

  const agentId = req.nextUrl.searchParams.get("agentId") ?? null;

  if (agentId) {
    const agent = await prisma.agent.findFirst({
      where: { id: agentId, orgId: org.id },
      select: { id: true },
    });
    if (!agent) {
      return NextResponse.json({ error: "Agent not found" }, { status: 404 });
    }
  }

  const pref = await prisma.alertPref.findFirst({
    where: { orgId: org.id, agentId },
  });

  if (!pref) {
    return NextResponse.json({ mode: "immediate", severityFloor: "warning" });
  }

  return NextResponse.json({ mode: pref.mode, severityFloor: pref.severityFloor });
}

export async function PUT(req: NextRequest) {
  const { orgId: clerkOrgId } = await auth();
  if (!clerkOrgId) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const parsed = AlertPrefUpdateSchema.safeParse(body);
  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
  }

  const { mode, severityFloor, agentId } = parsed.data;
  const resolvedAgentId = agentId ?? null;

  const org = await resolveOrg(clerkOrgId);
  if (!org) {
    return NextResponse.json({ error: "Organization not found" }, { status: 404 });
  }

  if (resolvedAgentId) {
    const agent = await prisma.agent.findFirst({
      where: { id: resolvedAgentId, orgId: org.id },
      select: { id: true },
    });
    if (!agent) {
      return NextResponse.json({ error: "Agent not found" }, { status: 404 });
    }
  }

  const existing = await prisma.alertPref.findFirst({
    where: { orgId: org.id, agentId: resolvedAgentId },
    select: { id: true },
  });

  if (existing) {
    await prisma.alertPref.update({
      where: { id: existing.id },
      data: { mode, severityFloor },
    });
  } else {
    await prisma.alertPref.create({
      data: { orgId: org.id, agentId: resolvedAgentId, mode, severityFloor },
    });
  }

  return NextResponse.json({ ok: true });
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@atlas/db";
import type { IncidentCategory } from "@atlas/shared";
import { evaluateTrace, translate, buildDedupKey, sendImmediateAlert } from "@atlas/evaluator";

export const maxDuration = 60;

const BATCH_SIZE = 5;
const MAX_ATTEMPTS = 3;

function backoffMinutes(attempts: number): number {
  return Math.min(60, Math.pow(2, attempts));
}

function addMinutes(date: Date, minutes: number): Date {
  return new Date(date.getTime() + minutes * 60_000);
}

export async function GET(req: NextRequest): Promise<NextResponse> {
  const cronSecret = process.env.CRON_SECRET;
  if (!cronSecret) {
    return NextResponse.json({ error: "Server misconfigured" }, { status: 500 });
  }
  const authHeader = req.headers.get("authorization");
  if (authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const now = new Date();

  const candidates = await prisma.$transaction(async (tx) => {
    const found = await tx.trace.findMany({
      where: {
        status: "received",
        OR: [
          { nextEvaluationAt: null },
          { nextEvaluationAt: { lte: now } },
        ],
      },
      select: { id: true },
      take: BATCH_SIZE,
      orderBy: { createdAt: "asc" },
    });

    if (found.length === 0) return [];

    const ids = found.map((t) => t.id);
    await tx.trace.updateMany({
      where: { id: { in: ids } },
      data: {
        status: "processing",
        nextEvaluationAt: addMinutes(now, 1.5),
        statusUpdatedAt: now,
      },
    });

    return ids;
  });

  if (candidates.length === 0) {
    return NextResponse.json({ processed: 0, passed: 0, incidents: 0, alerted: 0, errors: 0 });
  }

  const traces = await prisma.trace.findMany({
    where: { id: { in: candidates } },
    include: { agent: true },
  });

  let passed = 0;
  let incidents = 0;
  let alerted = 0;
  let errors = 0;

  for (const trace of traces) {
    try {
      const toolCalls = Array.isArray(trace.toolCalls) ? trace.toolCalls as Array<{ name: string; input: Record<string, unknown>; output?: unknown }> : [];

      const evalResult = await evaluateTrace({
        redactedPrompt: trace.redactedPrompt,
        redactedResponse: trace.redactedResponse,
        toolCalls,
        tokenCount: trace.tokenCount,
        platform: trace.agent.platform,
      });

      await prisma.evaluation.create({
        data: {
          traceId: trace.id,
          outcome: evalResult.outcome,
          pass: evalResult.outcome === "pass",
          category: evalResult.category ?? null,
          confidence: evalResult.confidence,
          businessImpact: evalResult.businessImpact,
          technicalReason: evalResult.technicalReason,
          reason: evalResult.technicalReason,
          model: evalResult.model,
        },
      });

      if (evalResult.outcome === "pass") {
        await prisma.trace.update({
          where: { id: trace.id },
          data: { status: "pass", statusUpdatedAt: new Date() },
        });
        passed++;
        continue;
      }

      const category = evalResult.category as IncidentCategory;
      const dedupKey = buildDedupKey(trace.agent.externalId, category);

      const dayStart = new Date(now);
      dayStart.setUTCHours(0, 0, 0, 0);

      const existingIncident = await prisma.incident.findFirst({
        where: {
          dedupKey,
          createdAt: { gte: dayStart },
        },
        select: { id: true },
      });

      if (existingIncident) {
        await prisma.trace.update({
          where: { id: trace.id },
          data: { status: "alerted", statusUpdatedAt: new Date() },
        });
        incidents++;
        continue;
      }

      await prisma.trace.update({
        where: { id: trace.id },
        data: { status: "evaluated", statusUpdatedAt: new Date() },
      });

      const rendering = await translate(evalResult, trace.agent.displayName);

      const severity: "warning" | "critical" = evalResult.confidence >= 0.85 ? "critical" : "warning";

      const incident = await prisma.$transaction(async (tx) => {
        const inc = await tx.incident.create({
          data: {
            traceId: trace.id,
            agentId: trace.agentId,
            orgId: trace.orgId,
            severity,
            category,
            summary: rendering.incidentSummary,
            dedupKey,
          },
        });

        await tx.trace.update({
          where: { id: trace.id },
          data: { status: "translated", statusUpdatedAt: new Date() },
        });

        return inc;
      });

      incidents++;

      const alertPref = await prisma.alertPref.findFirst({
        where: {
          orgId: trace.orgId,
          OR: [
            { agentId: trace.agentId },
            { agentId: null },
          ],
        },
        orderBy: { agentId: "desc" }, // agent-specific wins (non-null sorts last in desc)
      });

      const shouldAlert =
        !alertPref ||
        (alertPref.mode === "immediate" &&
          (alertPref.severityFloor === "warning" || severity === "critical"));

      if (shouldAlert) {
        const orgUser = await prisma.user.findFirst({
          where: { orgId: trace.orgId },
          select: { email: true },
        });

        if (orgUser?.email) {
          const alertResult = await sendImmediateAlert(
            {
              id: incident.id,
              severity,
              category,
              summary: rendering.incidentSummary,
              agentName: trace.agent.displayName,
            },
            orgUser.email,
            rendering.alertCopy,
          );

          await prisma.alert.create({
            data: {
              incidentId: incident.id,
              channel: "email",
              sentAt: new Date(),
              status: alertResult.status,
            },
          });

          if (alertResult.status === "sent") alerted++;
        }
      }

      await prisma.trace.update({
        where: { id: trace.id },
        data: { status: "alerted", statusUpdatedAt: new Date() },
      });

    } catch (err) {
      errors++;
      const attempts = trace.evaluationAttempts + 1;

      if (attempts >= MAX_ATTEMPTS) {
        await prisma.trace.update({
          where: { id: trace.id },
          data: {
            status: "failed",
            evaluationAttempts: attempts,
            statusUpdatedAt: new Date(),
          },
        });
      } else {
        await prisma.trace.update({
          where: { id: trace.id },
          data: {
            status: "received",
            evaluationAttempts: attempts,
            nextEvaluationAt: addMinutes(new Date(), backoffMinutes(attempts)),
            statusUpdatedAt: new Date(),
          },
        });
      }

      const errMsg =
        err instanceof Error ? err.name + ": " + err.message.slice(0, 200) : "unknown error";
      console.error(`[cron/evaluate] trace ${trace.id} failed (attempt ${attempts}): ${errMsg}`);
    }
  }

  return NextResponse.json({
    processed: candidates.length,
    passed,
    incidents,
    alerted,
    errors,
  });
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@clerk/nextjs/server";
import { prisma } from "@atlas/db";
import { INCIDENT_CATEGORIES } from "@atlas/shared";
import { z } from "zod";

const ALLOWED_CORRECT_CATEGORIES = new Set<string>([...INCIDENT_CATEGORIES, "none"]);

const FeedbackSchema = z.object({
  incidentId: z.string().min(1).max(64),
  correct: z.boolean(),
  correctCategory: z
    .string()
    .refine((v) => ALLOWED_CORRECT_CATEGORIES.has(v), "invalid category")
    .optional(),
  correctSeverity: z.enum(["warning", "critical", "none"]).optional(),
  note: z.string().max(1000).optional(),
});

export async function POST(req: NextRequest) {
  const { userId: clerkUserId } = await auth();
  if (!clerkUserId) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  let body: unknown;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const parsed = FeedbackSchema.safeParse(body);
  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
  }

  const { incidentId, correct, correctCategory, correctSeverity, note } = parsed.data;

  const user = await prisma.user.findUnique({
    where: { clerkUserId },
    select: { id: true, orgId: true },
  });
  if (!user) {
    return NextResponse.json({ error: "User not found" }, { status: 403 });
  }

  const incident = await prisma.incident.findFirst({
    where: { id: incidentId, orgId: user.orgId },
    select: { id: true },
  });
  if (!incident) {
    return NextResponse.json({ error: "Incident not found" }, { status: 404 });
  }

  const existing = await prisma.feedback.findFirst({
    where: { incidentId, userId: user.id },
    select: { id: true },
  });
  if (existing) {
    return NextResponse.json({ error: "Feedback already submitted" }, { status: 409 });
  }

  await prisma.feedback.create({
    data: {
      incidentId,
      userId: user.id,
      correct,
      correctCategory: correctCategory ?? null,
      correctSeverity: correctSeverity ?? null,
      note: note ?? null,
    },
  });

  return NextResponse.json({ ok: true }, { status: 201 });
}

